module sipo_shift_register (  
    input clk,  
    input reset,  
    input serial_in,  
    output reg [4:0] parallel_out  
);  
    reg [4:0] data_buffer;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            data_buffer <= 5'b0;  
        else  
            data_buffer <= {data_buffer[3:0], serial_in};  
    end  

    always @(*) begin  
        parallel_out = data_buffer;  
    end  
endmodule
